  "：用过 AI 必勾标识。案例：润色也算用 AI，不勾标识 → 平台自动加标 + 限流；违禁词命中 → 发后几秒 0 曝光。evidence: [T04-S006, T03-S007]"
  "：图文/测评/口播/资讯各不同。案例：图文干货 DeepSeek 搭结构 + 豆包人话化 + 稿定大字报；口播教程 豆包脚本 + 剪映智能字幕(不露脸用即梦数字人)。evidence: [T02-S020, T02-S005]"
  "：个人号不必养号。案例：新号直接发，前 3 篇测哪个方向破播放，发后 1-3 小时回前 10 条评论拉推荐权重。evidence: [T03-S005, T03-S001]"
  "：精做是合规护城河。案例：标准化品类(母婴可用度~90%)可适度批量；体验性品类(文旅~50%)必精做，全自动撞 AI 味限流。evidence: [T03-S001, T04-S004]"
  "：不看粉丝数虚荣指标。案例：互动率 <3% 即回炉改标题封面；每周拆自己的爆款找可复用结构。evidence: [T03-S005, T06-S001]"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
